CREATE TABLE students (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    email TEXT,
    age INTEGER
);

INSERT INTO students (name, email, age) VALUES
    ('Ahmet Yilmaz', 'ahmet@example.com', 20),
    ('Ayse Kaya', 'ayse@example.com', 21),
    ('Mehmet Demir', 'mehmet@example.com', 22);

-- Birlestirme (|| operatoru SQLite'da kullanilir)
SELECT name || ' - ' || email AS student_info
FROM students;

-- Buyuk/kucuk harf
SELECT UPPER(name) AS upper_name, LOWER(name) AS lower_name
FROM students;

-- Uzunluk
SELECT name, LENGTH(name) AS name_length
FROM students;

-- Alt metin alma (SUBSTR)
SELECT name, SUBSTR(name, 1, 3) AS short_name
FROM students;

-- TRIM ile bosluk temizleme
SELECT TRIM('  Merhaba  ') AS trimmed;

-- REPLACE ile degistirme
SELECT REPLACE(email, '@example.com', '@school.edu') AS new_email
FROM students;

-- Birden fazla parcayi birlestirme (CONCAT_WS yerine || ile)
SELECT name || ' | ' || email || ' | ' || age AS combined
FROM students;

-- Isim soyisim ayirma (INSTR ve SUBSTR ile)
SELECT
    name,
    SUBSTR(name, 1, INSTR(name, ' ') - 1) AS first_name,
    SUBSTR(name, INSTR(name, ' ') + 1) AS last_name
FROM students;
